| EntryOrExit | Integer | 发送委托单的<a href="/helper?product_id=999&search= 开平仓类型 &type=search" target=_blank> 开平仓类型 </a>，取值为Enum_Entry,Enum_Exit,Enum_ExitToday之一 |
| lot    | Numeric | 手数 |
| price  | Numeric | 价格 |
| orderIds | ArrayRef&lt;Integer&gt; | 报单索引 |
| userNote | String | 用户注释 |
| createSource | String | 操作源 |
| accountIndex | Integer | 账户下标索引 |

**返回值：**

| 类型 | 说明 |
| ---- | ---- |
| Bool | True表示发单成功，False表示发单失败 |

**示例：**

```cpp
Vars
    Global Integer sendCount(0);
    Global Integer fillCount(0);
Events
    OnReady()
    {
        //根据操作源订阅委托
        Bool ret = A_SubscribeTradeByCreateSource(A_GetOrderCreateSource);
        Print("A_SubscribeTradeByCreateSource:" + IIFString(ret, "True", "False"));
    }

    OnBar(ArrayRef<Integer> indexs)
    {
        if(BarStatus == 2 && sendCount == 0)
        {//发开仓单
            Array<Integer> orders;
            //账户下单操作
            Bool ret = A_SendOrderEx(Enum_Buy, Enum_Entry, 3, Q_AskPrice, orders, "", A_GetOrderCreateSource);
            Print("Buy,A_SendOrderEx:" + IIFString(ret, "True", "False") + "," + TextArray(orders));
            if(ret)
            {
                sendCount = sendCount + 1;
            }
        }
        if(BarStatus == 2 && sendCount > 0 && sendCount <= fillCount)
        {//发平仓单
            Array<Integer> orders;
            //账户下单操作
            Bool ret = A_SendOrderEx(Enum_Sell, Enum_Exit, 1, Q_BidPrice, orders, "", A_GetOrderCreateSource);
            Print("Sell,A_SendOrderEx:" + IIFString(ret, "True", "False") + "," + TextArray(orders));
            sendCount = -1;
        }
    }

    OnFill(FillRef ordFill)
    {
        fillCount = fillCount + 1;
        Print("fillCount:" + Text(fillCount));
    }
```

